#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <sys/types.h>
#include <wait.h>

void child_handler(int sig) {
 printf("Child received signal %d\n", sig);
 exit(0);
}

int main() {
 pid_t pid = fork();

 if (pid == 0) {
 // Child process
 signal(SIGUSR1, child_handler);
 printf("Child waiting for signal...\n");
 while(1) sleep(1);
 } else {
 // Parent process
 sleep(1);
 printf("Parent sending SIGUSR1 to child\n");
 kill(pid, SIGUSR1);
 wait(NULL);
 printf("Child terminated\n");
 }
 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <stdlib.h>

void cleanup_handler(int sig) {
 printf("\nCleanup: Closing files and releasing resources...\n");
 printf("Signal %d received, terminating gracefully\n", sig);
 exit(0);
}

int main() {
 printf("Program started, setting signal handler...\n");

 // Set handler for SIGTERM
 signal(SIGTERM, cleanup_handler);

 printf("Sending SIGTERM to self using raise()...\n");
 raise(SIGTERM);

 // This line never executes
 printf("This won't print\n");
 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>
#include <errno.h>

int process_exists(pid_t pid) {
 if (kill(pid, 0) == 0) {
 return 1; // Process exists
 } else {
 if (errno == ESRCH) {
 return 0; // No such process
 } else if (errno == EPERM) {
 return 1; // Exists but no permission
 }
 return 0;
 }
}

int main() {
 pid_t my_pid = getpid();
 pid_t invalid_pid = 99999;

 printf("Checking process %d exists: %s\n", 
 my_pid, process_exists(my_pid) ? "YES" : "NO");

 printf("Checking process %d exists: %s\n", 
 invalid_pid, process_exists(invalid_pid) ? "YES" : "NO");

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>
#include <stdlib.h>

void handler(int sig) {
 printf("Caught signal %d\n", sig);
}

int main() {
 struct sigaction sa;

 // Set up sigaction structure
 sa.sa_handler = handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;

 // Register handler for SIGINT
 if (sigaction(SIGINT, &sa, NULL) == -1) {
 perror("sigaction");
 exit(1);
 }

 printf("Press Ctrl+C to trigger handler\n");
 while(1) {
 sleep(1);
 }

 return 0;
}
